fn read_number(s: &str) -> Result<i32, String> {
    s.parse::<i32>().map_err(|e| e.to_string())
}

match read_number("42") {
    Ok(n)  => println!("Got: {}", n),
    Err(e) => eprintln!("Error: {}", e),
}

