def read_number(s: str) -> int:
    try:
        return int(s)
    except ValueError as e:
        raise ValueError(str(e)) from e

try:
    n = read_number("42")
    print(f"Got: {n}")
except ValueError as e:
    print(f"Error: {e}", file=sys.stderr)

